<template>
    <canvas id="canvas" />
</template>

<script>
    export default{
        name: "NeonCanvasTest",
        mounted(){
            init();
        },
    }

    var myGameArea;

    function init(){
        myGameArea = new NewGameArea('canvas');
        window.addEventListener('resize', function(){ myGameArea.resizeCanvas(); }, false);

        //Start Update
        requestAnimationFrame(updateAndDraw);
        //setInterval(updateAndDraw, 0);
    }

    var settings ={
        lineLength: 75,
        speed: 1,
        angle: 60,
        particleSpeed: 1000,
        particleSize: 1,
        timeToFill: 1,

        offset: 780,

        deltaTime: 0.005
    }

    var fps = 60,
        start = Date.now();
    function updateAndDraw(){
        requestAnimationFrame(updateAndDraw);

        //Calcuate DeltaTime
        var now = Date.now();
        var elapsed = now - start;
        start = now;

        settings.deltaTime = elapsed / 1000.0;
        myGameArea.update();
    }

    function randomMax(max) {
        return Math.floor(Math.random() * max);
    }
    function randomMinMax(min, max) {
        return Math.random() * (max - min) + min;
    }
    
    function toRadians(angle){
        return angle * Math.PI / 180;
    }
    function rotate(vec, angle){
        angle = toRadians(angle);
        return [((vec[0] * Math.cos(angle)) - (vec[1] * Math.sin(angle))), 
                ((vec[0] * Math.sin(angle)) + (vec[1] * Math.cos(angle)))];
    }
    const lerp = (x, y, a) => x * (1 - a) + y * a;

    class Canvas2D{
        constructor(canvasId, width, height){
            this.canvas = document.getElementById(canvasId);
            this.ctx = this.canvas.getContext('2d');

            this.resize(width, height);
        }

        clear(color){
            this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
        }

        getContext(){
            return this.ctx;
        }

        get height(){
            return this.canvas.height;
        }

        get width(){
            return this.canvas.width;
        }

        resize(width, height){
            this.canvas.width = width;
            this.canvas.height = height;
        }
    }

    class Sprite{
        constructor(x, y, radius, color){
            this.x = x;
            this.y = y;
            this.radius = radius;
            this.color = color;
        }

        draw(ctx){
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.radius, 0, Math.PI*2);
            ctx.fillStyle = this.color;
            ctx.shadowBlur = this.radius * 2;
            ctx.shadowColor = this.color;
            ctx.fill();
            ctx.closePath();

            this.onDraw(ctx);
        }

        onDraw(ctx){
            //Defined by child classes
        }

        destroy(){
            
        }

        getColor(){
            return this.color;
        }

        setPosition(x, y){
            this.x = x;
            this.y = y;
        }

        setRadius(radius){
            this.radius = radius;
        }
        
        setColor(color){
            this.color = color;
        }
    }

    class SparkParticle extends Sprite{
        constructor(x, y, dir, color){
            super(x, y, 1, 'green');

            this.dir = dir;

            this.setColor(color);

            this.lifetime = randomMinMax(0.5, 0.7);
            this.age = this.lifetime;

            this.maxRadius = 10;
            this.setRadius(this.maxRadius);
            this.speed = 1;
        }

        update(){
            this.age -= settings.deltaTime * this.speed;
            if(this.age < 0){
                return false;
            }

            this.x += this.dir[0] * this.speed;
            this.y += this.dir[1] * this.speed;

            //Decrease size based on current age
            this.setRadius(this.maxRadius / (this.lifetime / this.age));

            return true;
        }
    }

    class HexParticle extends Sprite{
        constructor(x, y, dir){
            super(x, y, 1, 'green');
            this.dir = dir;
            this.age = 0;
            this.setRadius(settings.particleSize);

            this.startX = x;
            this.startY = y;
            this.originX = x;
            this.originY = y;

            //Array of all positions the line has travelled to
            this.positions = [];
            this.stop = false;
        }

        update(){
            if(this.stop) return;
            let speed = settings.particleSpeed;
            this.x += this.dir[0] * speed * settings.deltaTime;
            this.y += this.dir[1] * speed * settings.deltaTime;

            this.age += (settings.deltaTime * speed);
            if(this.age >= settings.lineLength){
                //Offset
                this.age -= settings.lineLength;
                if(this.age > 0.1){
                    this.x -= this.dir[0] * this.age;
                    this.y -= this.dir[1] * this.age;
                }
                

                this.age = 0;
                let angles = [60, -60]

                this.dir = rotate(this.dir, angles[randomMax(2)]);

                //Add to list of positions to draw each line
                this.positions.push([this.x, this.y]);

                if(this.x >= (this.originX + settings.offset) || this.x <= (this.originX - settings.offset) 
                || this.y >= (this.originY + settings.offset) || this.y <= (this.originY - settings.offset)){
                    this.stop = true;
                }
            }
        }

        draw(ctx){
            //Draw all positions
            ctx.beginPath();
            ctx.strokeStyle = this.color;
            ctx.moveTo(this.startX, this.startY);
            ctx.shadowBlur = 10;
            ctx.shadowColor = this.color;
            for(let i = 0; i < this.positions.length; ++i){
                ctx.lineTo(this.positions[i][0], this.positions[i][1]);
            }

            //Draw current
            ctx.lineTo(this.x, this.y);
            ctx.stroke();
        }
    }

    class NewBall extends Sprite{
        constructor(x, y){
            super(x, y, 1, 'green');

            this.maxSize = 50;
            this.age = 10;
            this.speed = 40;

            this.increase = true;

            this.particleList = [];

            this.minSpawnTime = 0.1;
            this.maxSpawnTime = 0.15;
            this.particleSpawnTimer = randomMinMax(this.minSpawnTime, this.maxSpawnTime);
        }

        destroy(){
            //Destroy Particles
            for(let i = 0; i < this.particleList.length; ++i){
                delete this.particleList[i];
            }

            delete this.particleList;
        }

        update(){
            //Update Colour
            this.setColor('hsl(' + ((Date.now() / 100.0) % 360.0) + ', 90%, 70%)');

            //Spawn Particles
            this.particleSpawnTimer -= settings.deltaTime;
            if(this.particleSpawnTimer <= 0){
                this.particleSpawnTimer = randomMinMax(this.minSpawnTime, this.maxSpawnTime);

                let dir = rotate([1, 0], randomMinMax(0, 360));
                let x = this.x + (dir[0] * this.radius);
                let y = this.y + (dir[1] * this.radius);
                this.particleList.push(new SparkParticle(x, y, dir, this.color));
            }

            //Update Particles
            for(let i = 0; i < this.particleList.length; ++i){
                if(!this.particleList[i].update()){
                    //Particle Dead, remove
                    this.particleList.splice(i, 1);
                }
            }

            //Update Size
            if(this.increase){
                this.age += settings.deltaTime * this.speed;
                if(this.age > 90) this.increase = false;
            }
            else{
                this.age -= settings.deltaTime * this.speed;
                if(this.age < 10) this.increase = true;
            }

            this.setRadius(Math.abs(Math.sin(toRadians(this.age)) * this.maxSize));
        }

        onDraw(ctx){
            //Draw Particles
            for(let i = 0; i < this.particleList.length; ++i){
                this.particleList[i].draw(ctx);
            }
        }
    }

    class GameState{
        static Pulse = new GameState("Pulse");
        static Hex = new GameState("Hex");

        constructor(state){
            this.state = state;
        }
    }

    class NewGameArea{
        constructor(canvasId){
            this.canvas = new Canvas2D(canvasId, 100, 100);
            this.resizeCanvas();

            this.state = GameState.Pulse;

            this.ball = new NewBall(this.canvas.width/2, this.canvas.height/2);
            //this.hexParticleSize = 100;
            this.hexParticles = [];
            //this.hexParticles.push(new HexParticle(this.canvas.width/2, this.canvas.height/2, directions[0]));
            //this.hexParticles.push(new HexParticle(this.canvas.width/2 + 1500, this.canvas.height/2, directions[0]));
            //this.hexParticles.push(new HexParticle(this.canvas.width/2 - 1500, this.canvas.height/2, directions[0]));
            //for(let i = 0; i < this.hexParticleSize - 3; ++i){
            //    this.hexParticles.push(new HexParticle(this.canvas.width/2, this.canvas.height/2, directions[randomMax(3)]));
            //}

            var that = this;
            document.getElementById(canvasId).addEventListener("mousedown", function(e){
                that.OnMouseDownEvent(e);
            });

            //document.addEventListener("keydown", function(e){
            //    if(e.code === 'Space' && !e.repeat){
            //        that.OnMouseDownEvent(e);
            //    }
            //});


            //Testing
            this.particleList = [];
        }

        update(){
            this.canvas.clear();

            switch(this.state){
                case GameState.Pulse:
                    if(this.ball != undefined){
                        this.ball.update();
                        this.ball.draw(this.canvas.getContext());
                    }
                    break;

                case GameState.Hex:
                    //Testing
                    let ctx = this.canvas.getContext();
                     for(let x = 0; x < 20; ++x){
                        for(let y = 0; y < 20; y++){
                            if(!this.particleList[x][y].active) continue;

                            let posX = this.particleList[x][y].posX;
                            let posY = this.particleList[x][y].posY;
                            ctx.beginPath();
                            ctx.strokeStyle = this.color;
                            ctx.shadowBlur = 5;
                            ctx.shadowColor = 'white';

                            if(this.particleList[x][y].finished){
                                //Draw Lines Fully
                                if(x+1 < 20 && (Math.abs(posX - this.particleList[x+1][y].posX)) <= settings.lineLength){
                                    ctx.moveTo(posX, posY);
                                    ctx.lineTo(this.particleList[x+1][y].posX, this.particleList[x+1][y].posY);
                                    ctx.stroke();
                                }

                                if(x-1 >= 0 && (Math.abs(posX - this.particleList[x-1][y].posX)) <= settings.lineLength){
                                    ctx.moveTo(posX, posY);
                                    ctx.lineTo(this.particleList[x-1][y].posX, this.particleList[x-1][y].posY);
                                    ctx.stroke();
                                }

                                if(y+1 < 20){
                                    ctx.moveTo(posX, posY);
                                    ctx.lineTo(this.particleList[x][y+1].posX, this.particleList[x][y+1].posY);
                                    ctx.stroke();
                                }

                                if(y-1 >= 0){
                                    ctx.moveTo(posX, posY);
                                    ctx.lineTo(this.particleList[x][y-1].posX, this.particleList[x][y-1].posY);
                                    ctx.stroke();
                                }
                            }
                            else{
                                //Draw Lines Partial
                                this.particleList[x][y].alpha += settings.deltaTime * 40;
                                let alpha = this.particleList[x][y].alpha;
                                if(alpha >= 1){
                                    this.particleList[x][y].finished = true;

                                    //Set neighbour points active
                                    if(x+1 < 20 && (Math.abs(posX - this.particleList[x+1][y].posX)) <= settings.lineLength){
                                        this.particleList[x+1][y].active = true;
                                    }

                                    if(x-1 >= 0 && (Math.abs(posX - this.particleList[x-1][y].posX)) <= settings.lineLength){
                                        this.particleList[x-1][y].active = true;
                                    }

                                    if(y+1 < 20){
                                        this.particleList[x][y+1].active = true;
                                    }

                                    if(y-1 >= 0){
                                        this.particleList[x][y-1].active = true;
                                    }

                                    continue;
                                }

                                let lerpX = 0;
                                let lerpY = 0;
                                if(x+1 < 20 && (Math.abs(posX - this.particleList[x+1][y].posX)) <= settings.lineLength){
                                    ctx.moveTo(posX, posY);
                                    lerpX = lerp(posX, this.particleList[x+1][y].posX, alpha)
                                    lerpY = lerp(posY, this.particleList[x+1][y].posY, alpha);
                                    ctx.lineTo(lerpX, lerpY);
                                    ctx.stroke();
                                }

                                if(x-1 >= 0 && (Math.abs(posX - this.particleList[x-1][y].posX)) <= settings.lineLength){
                                    ctx.moveTo(posX, posY);
                                    lerpX = lerp(posX, this.particleList[x-1][y].posX, alpha)
                                    lerpY = lerp(posY, this.particleList[x-1][y].posY, alpha);
                                    ctx.lineTo(lerpX, lerpY);
                                    ctx.stroke();
                                }

                                if(y+1 < 20){
                                    ctx.moveTo(posX, posY);
                                    lerpX = lerp(posX, this.particleList[x][y+1].posX, alpha)
                                    lerpY = lerp(posY, this.particleList[x][y+1].posY, alpha);
                                    ctx.lineTo(lerpX, lerpY);
                                    ctx.stroke();
                                }

                                if(y-1 >= 0){
                                    ctx.moveTo(posX, posY);
                                    lerpX = lerp(posX, this.particleList[x][y-1].posX, alpha)
                                    lerpY = lerp(posY, this.particleList[x][y-1].posY, alpha);
                                    ctx.lineTo(lerpX, lerpY);
                                    ctx.stroke();
                                }
                            }
                        }
                    }

                    //for(let i = 0; i < this.hexParticles.length; ++i){
                    //    this.hexParticles[i].update();
                    //    this.hexParticles[i].draw(this.canvas.getContext());
                    //}
                    break;
            }
        }

        resizeCanvas(){
            this.canvas.resize(window.innerWidth, window.innerHeight);

            //Todo: Reposition Particles and Ball object
            if(this.ball != undefined){
                this.ball.setPosition(this.canvas.width/2, this.canvas.height/2);
            }

            //Speed = Distance / Time
            settings.particleSpeed = (this.canvas.width / settings.timeToFill) * 1.5;
        }

        //Events
        OnMouseDownEvent(e){
            console.log(settings.deltaTime);

            if(this.state === GameState.Hex || this.ball == undefined) return;
            
            //for(let i = 0; i < this.hexParticles.length; ++i){
            //    this.hexParticles[i].setColor(this.ball.getColor());
            //}

            //Destroy Ball Object
            this.color = this.ball.getColor();
            this.ball.destroy();
            delete this.ball;
            this.ball = undefined;

            //Spawn Hex Particles
            let directions = [
                [1, 0],
                rotate([1, 0], 120),
                rotate([1, 0], 240)
            ]
            this.hexParticles.push(new HexParticle(this.canvas.width/2, this.canvas.height/2, directions[0]));
            this.hexParticles.push(new HexParticle(this.canvas.width/2, this.canvas.height/2, directions[1]));
            this.hexParticles.push(new HexParticle(this.canvas.width/2, this.canvas.height/2, directions[2]));

            this.hexParticles.push(new HexParticle(this.canvas.width/2 - settings.offset, this.canvas.height/2, directions[0]));
            this.hexParticles.push(new HexParticle(this.canvas.width/2 - settings.offset, this.canvas.height/2, directions[1]));
            this.hexParticles.push(new HexParticle(this.canvas.width/2 - settings.offset, this.canvas.height/2, directions[2]));

            this.hexParticles.push(new HexParticle(this.canvas.width/2 + settings.offset, this.canvas.height/2, directions[0]));
            this.hexParticles.push(new HexParticle(this.canvas.width/2 + settings.offset, this.canvas.height/2, directions[1]));
            this.hexParticles.push(new HexParticle(this.canvas.width/2 + settings.offset, this.canvas.height/2, directions[2]));


            //Construct Points
            for(let x = 0; x < 20; ++x){
                this.particleList[x] = [];
                for(let y = 0; y < 20; ++y){
                    //this.particleList[x][y] = [0, 0];
                }
            }

            let xOffset = (rotate([1, 0], 60)[0] * settings.lineLength);
            let yOffset = (rotate([1, 0], 60)[1] * settings.lineLength);
            for(let x = 0; x < 20; ++x){
                for(let y = 0; y < 20; y+=2){
                    let xHalf = Math.floor(x/2);
                    let positionX = (x * settings.lineLength) + (xHalf * settings.lineLength);
                    let positionY = (y * yOffset);

                    this.particleList[x][y] = 
                    {
                        posX: positionX,
                        posY: positionY,
                        active: false,
                        alpha: 0.0,
                        finished: false
                    };
                }
            }

            for(let x = 0; x < 20; ++x){
                for(let y = 1; y < 20; y+=2){
                    let xHalfUp = Math.ceil(x/2);
                    let positionX = (-xOffset + (x*settings.lineLength) + (xHalfUp * settings.lineLength));
                    let positionY = (y * yOffset);
                    
                    this.particleList[x][y] = 
                    {
                        posX: positionX,
                        posY: positionY,
                        active: false,
                        alpha: 0.0,
                        finished: false
                    };
                }
            }

            //Set random points to be active to start the chain
            
            this.particleList[randomMax(20)][randomMax(20)].active = true;
            this.particleList[randomMax(20)][randomMax(20)].active = true;
            this.particleList[randomMax(20)][randomMax(20)].active = true;
            this.particleList[randomMax(20)][randomMax(20)].active = true;

            //Change State
            this.canvas.clear();
            this.state = GameState.Hex;
        }
    }
</script>

<style scoped>
    #canvas{
        position: fixed;
        z-index: -1;
        top: 0;
        left: 0;
        margin: 0;
        cursor: pointer;
        width: 100%;

        outline: none;
        -webkit-tap-highlight-color: rgba(255, 255, 255, 0); /* mobile webkit */
    }
</style>